import React from 'react';
import { motion } from 'framer-motion';
import { FaUniversity, FaMapMarkerAlt, FaLightbulb, FaUsers } from 'react-icons/fa';
import './About.css';

const About = () => {
  const highlights = [
    {
      icon: <FaUniversity />,
      title: "M.Sc. Mathematics",
      subtitle: "Ghent University, Belgium"
    },
    {
      icon: <FaMapMarkerAlt />,
      title: "Based in Belgium",
      subtitle: "Open to EU opportunities"
    },
    {
      icon: <FaLightbulb />,
      title: "10+ Years",
      subtitle: "Analytical Experience"
    },
    {
      icon: <FaUsers />,
      title: "Multi-Domain",
      subtitle: "Business, Finance, Healthcare"
    }
  ];

  return (
    <section id="about" className="about section">
      <div className="container">
        <motion.h2
          className="section-title"
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5 }}
        >
          About Me
        </motion.h2>

        <div className="about-content">
          <motion.div
            className="about-text"
            initial={{ opacity: 0, x: -50 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            <p>
              I'm a <strong>Computational Scientist</strong> bridging the gap between 
              <span className="gradient-text"> theoretical mathematics</span> and 
              <span className="gradient-text"> computational intelligence</span>. I architect 
              algorithmic solutions that transform complex mathematical frameworks into 
              practical, production-ready systems for Business, Finance, Healthcare, and Defense.
            </p>

            <p>
              Currently at <strong>Ghent University, Belgium</strong>, I'm advancing computational 
              methods for <strong>Reducing Bias in Likelihood Ratio Tests for Structural Equation 
              Modelling</strong> — developing algorithms that distinguish true causal mechanisms 
              from statistical artifacts in high-dimensional, multi-domain environments.
            </p>

            <p>
              My computational approach synthesizes <strong>10+ years</strong> spanning pure 
              mathematics, statistical theory, entrepreneurship, and ML engineering. I build 
              systems where mathematical proofs meet real-world data — from causal inference 
              engines to neural-symbolic architectures that require both theoretical soundness 
              and computational efficiency.
            </p>

            <div className="about-details">
              <div className="detail-item">
                <strong>🔬 Computational Focus:</strong> Causal Inference, SEM, Neural-Symbolic AI, Algorithm Design
              </div>
              <div className="detail-item">
                <strong>📍 Location Timeline:</strong> India (until Aug 2025) → Ghent, Belgium (Sep 2025 - Present)
              </div>
              <div className="detail-item">
                <strong>🧮 Mathematical Tools:</strong> R/lavaan, Python/NumPy, MATLAB, Computational Statistics
              </div>
              <div className="detail-item">
                <strong>🌐 Languages:</strong> English (C2), Hindi (C2), Gujarati (Native), Dutch (Learning 🇧🇪)
              </div>
            </div>
          </motion.div>

          <motion.div
            className="highlights-grid"
            initial={{ opacity: 0, x: 50 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            {highlights.map((item, index) => (
              <motion.div
                key={index}
                className="highlight-card glow-box"
                whileHover={{ scale: 1.05 }}
                transition={{ type: 'spring', stiffness: 300 }}
              >
                <div className="highlight-icon">{item.icon}</div>
                <div className="highlight-title">{item.title}</div>
                <div className="highlight-subtitle">{item.subtitle}</div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </div>
    </section>
  );
};

export default About;
